const sd = $getWorkflowStaticData('global');
const body = $json.body || $json;
const MIX_IDX = 4;
const FOLEY_IDX = 2;
const p = (sd.projects || []).find(x => x.id === body.projectId);
if (!p) throw new Error('Project not found');
if (body.action === 'advance') {
  if (p.idx + 1 === MIX_IDX && !p.foley) throw new Error('Foley review required before final mix');
  if (p.idx >= 6) return [{ json: { ok: true, skipped: true } }];
  p.idx++;
  if (p.idx > 0) p.shot = true;
  if (p.idx === MIX_IDX && !p.mixStart) {
    const d = new Date();
    p.mixStart = `${d.getDate()}/${d.getMonth() + 1}`;
  }
}
if (body.action === 'foley_confirm') {
  if (p.idx < FOLEY_IDX) throw new Error('Not at foley stage yet');
  p.foley = true;
}
const msg = `📢 تحديث مشروع «${body.project}»\n👤 ${body.student}\n${body.fromStage} → ${body.toStage}${body.note ? '\n📝 ' + body.note : ''}`;
return [{ json: { ok: true, notifyMessage: msg, notifyPhones: (sd.professors || []).map(x => x.phone) } }];

const sd = $getWorkflowStaticData('global');
const body = $json.body || $json;
if (!sd.bookings) sd.bookings = [];
const clash = sd.bookings.find(b => b.date === body.date && b.slot === body.slot);
if (clash) return [{ json: { clash: true, id: null } }];
const p = (sd.projects || []).find(x => x.id === body.projectId);
if (body.purpose && body.purpose.includes('المكساج') && p && !p.foley) {
  throw new Error('Foley review required before mix booking');
}
const id = 'BK' + Math.floor(1000 + Math.random() * 9000);
sd.bookings.push({ id, projectId: body.projectId, project: body.project, student: body.student, phone: body.phone || '', date: body.date, slot: body.slot, purpose: body.purpose, supervisor: null });
const msg = `🎙️ حجز استوديو جديد\n📽 ${body.project} — ${body.student}\n📅 ${body.date} | ${body.slot}\n🎯 ${body.purpose}`;
return [{ json: { id, clash: false, notifyMessage: msg, notifyPhones: (sd.professors || []).map(x => x.phone) } }];

const sd = $getWorkflowStaticData('global');
const body = $json.body || $json;
const b = (sd.bookings || []).find(x => x.id === body.bookingId);
if (!b) throw new Error('Booking not found');
if (b.supervisor) return [{ json: { taken: true, supervisor: b.supervisor } }];
b.supervisor = body.professor;
const msg = `✅ تم تسجيل الإشراف\n👨‍🏫 ${body.professor}\n📽 ${b.project}\n📅 ${b.date} | ${b.slot}`;
return [{ json: { taken: false, ok: true, notifyMessage: msg, studentPhone: b.phone || '' } }];
